var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"제 6 난민지구 <color=#ffd34c>멘델슨의 피라미드 파워 클리닉</color> \\n<color=#ffd34c>호라이즌</color>, 상황 대기중","JPN":"第6難民地区<color=#ffd34c>メンデルソンのピラミッド・パワークリニック</color>\\n<color=#ffd34c>ホライズン</color>、状況待機中","ENG":"<color=#ffd34c>Mendelssohn's Pyramid Power Clinic</color>, 6th Refuge District\\n<color=#ffd34c>Horizon</color> on standby\xA0","TWN":"第六難民區 <color=#ffd34c>曼德森金字塔能量診所</color> \\n<color=#ffd34c>地平線</color>，待命中。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"엠마는 어떻습니까, 휴먼.","JPN":"エマの様子はどうですか、ヒューマン。","ENG":"How is Emma doing, human?","TWN":"人類，愛瑪情況如何？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"위험한 고비는 넘겼대. 신비한 피라미드 파워 어쩌고는 못 믿겠지만.","JPN":"峠は越えたみたい。神秘的なピラミッドパワーなんて信用できないけどね……","ENG":"The worst is over. Although I don't buy into the whole mystical pyramid power nonsense.","TWN":"已經度過危險期，雖然我不相信什麼神秘的金字塔力量還什麼的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"내일 날이 밝으면 큰 병원으로 이송할 거야. 거기라면 그 얼간이들도 얼씬거리지 않겠지.","JPN":"夜が明けたら大きい病院に移送するって。そこならあの気色悪い連中も追いかけてこないと思う。","ENG":"They'll transfer her to a bigger hospital tomorrow morning. I bet those jerks wouldn't dare prowl around there.","TWN":"等明天天一亮就要立刻送到大醫院去，相信在人來人往的大醫院裡，那些人也不敢怎麼樣吧！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그 자들이 무섭지는 않습니까?","JPN":"彼らが怖くないのですか？","ENG":"You do not fear them?","TWN":"你不怕那些人嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"별로. 여긴 눈만 마주쳐도 죽여 버린다고 총 들이미는 동네인데 뭐.","JPN":"別に。ここは目が合っただけで殺してやるって銃口を向けられる街なんだから。","ENG":"Not really. I mean, Everyone in this neighborhood threatens to shoot you dead if you look at them funny.","TWN":"有什麼好怕的！在這個地方，只要隨便和人對到眼，就會有人拿槍抵著你的頭好嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그런 의미에서 넌 진짜 운 좋은 거야.","JPN":"そういう意味であんたは本当に運がいいんだよ。","ENG":"Speaking of which, you're super lucky.","TWN":"真的是算你運氣好！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"나 죽여 줍쇼, 하고 뛰어나갔는데 멀쩡하잖아.","JPN":"殺してくれーって突っ込んで行ったのと同然なのに無事だったんだから。","ENG":"You were pretty much asking them to kill you, but you came out unscathed.","TWN":"就這樣跑出去找死，還可以毫髮無傷。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"통상의 개인화기로는 제 기동을 멈출 수 없습니다.","JPN":"通常の小火器で私の機動を止めることはできません。","ENG":"Ordinary firearms cannot halt my operation.","TWN":"普通人是無法對我怎麼樣的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"으이그, 어련하시겠어.","JPN":"はいはい、そうでしたね。","ENG":"Right, right. I'm sure.","TWN":"好啦好啦，好棒棒～"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제 머리를 쓰다듬는 행동은 삼가해 주십시오. 휴먼.","JPN":"私の頭を撫でる行動はお控えください、ヒューマン。","ENG":"Please refrain from patting my head, human.","TWN":"人類，請不要觸碰我的頭。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"대견해서 그런다, 왜?","JPN":"えらいえらいしてあげるだけだよ、嫌なの？","ENG":"I'm just proud of you, okay?","TWN":"就覺得你很棒嘛～怎樣？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"상으로 언니랑 집에 가서 단둘이 넷플렉스 볼래? 어른의 세계를 알려 줄까?","JPN":"ご褒美にお姉ちゃんの部屋に行って二人で面白い動画でもみる？　大人の世界を教えてあげるよ。","ENG":"How about we go watch Webflix back at my place as a reward? We can chill like real grown ups.","TWN":"就當作獎勵，要不要去我家看Netflex？想知道大人的世界嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그런 무의미한 시간 낭비에는 관심없습니다.","JPN":"そんな無意味な時間の無駄使いには興味ありません。","ENG":"I see little point in wasting time like that.","TWN":"那種浪費時間的事我沒興趣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"쑥스러워서 그러는 거지? 나 다 알거든?","JPN":"照れてるだけでしょ？　お姉ちゃんには全部お見通しなんだから！","ENG":"Aww, you're just being shy, aren't you? I can totally tell.","TWN":"是不是害羞～？哎呀～跟我客氣什麼！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"레이첼!","JPN":"レイチェル！","ENG":"Rachel!","TWN":"瑞秋！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 원장님!","JPN":"あ、院長！","ENG":"Oh, headmaster!","TWN":"喔，院長！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"자경단한테 얘기 들었다. 엠마는 무사하니?","JPN":"自警団から話は聞いた。エマは無事か？","ENG":"The neighborhood watch told me all about it. Is Emma okay?","TWN":"我聽自衛隊的人說了，愛瑪沒事吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"막 잠들었어요. 피를 많이 흘려서 당분간 안정을 취해야 한대요.","JPN":"ちょうど眠ったところです。\\n出血が多すぎてしばらくは安静にしなければならないようです。","ENG":"She just fell asleep. They say she needs plenty of rest because she lost so much blood.","TWN":"她剛睡著。她失血過多，短時間內需要好好休養。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"다행이구나. 애가 총을 맞았다는 소리를 듣고 어찌나 놀랐는지.","JPN":"よかった。あの子が撃たれたという話を聞いてあまりにも驚いて……","ENG":"Thank goodness. I was so shocked when I heard she got shot.","TWN":"那就好，聽到她中槍的事快把我嚇死。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"레이첼 너는? 어디 다친 데는 없고?","JPN":"レイチェル、君は大丈夫か？　ケガは？","ENG":"How about you, Rachel? Are you unhurt?","TWN":"瑞秋，那你呢？你有受傷嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"전 괜찮아요. 호라이즌 덕분에요.","JPN":"アタシは……平気です。ホライズンのおかげで。","ENG":"I'm fine. All thanks to Horizon.","TWN":"我…我沒事，幸好有地平線在。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"저 애가……?","JPN":"あの子が……？","ENG":"That little kid?","TWN":"你說她……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"네. 쟤가 그 놈들을 유인해 주지 않았으면 저나 엠마나 모두 죽었을지도 몰라요.","JPN":"はい、あの子が犯人たちを引き付けてくれなかったら、アタシもエマも死んでいたかもしれません。","ENG":"Yes. If she didn't lure those jerks away, both Emma and I might be dead by now.","TWN":"是，要不是有她引開壞人的注意，我跟愛瑪可能早就小命不保！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"이제 눈칫밥 안 주실 거죠? 엠마한테는 생명의 은인이잖아요?","JPN":"これからは優しくしてあげてくださいよ？　エマにとっては生命の恩人じゃないですか。","ENG":"You're not going to kick her out anymore, right? I mean, she saved Emma's life!","TWN":"院長不會不收留她對吧？她可是愛瑪的救命恩人欸！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"크흠…….","JPN":"こほん……","ENG":"Ahem…","TWN":"咳咳……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"레이첼, 그간 내가 말은 안 했지만 오늘 확실하게 짚고 넘어가야겠다.","JPN":"レイチェル、今まで黙っていたが、今日ははっきり言っておく。","ENG":"Rachel, I've never said this explicitly, but let me make things clear once and for all.","TWN":"瑞秋，雖然我之前都沒跟你說，但今天就把話說清楚吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"우리 보육원은 저 애를 받을 수 없어. 엠마의 은인이라도 마찬가지야.","JPN":"うちの施設はあの子を受け入れられない。エマの恩人でもだ。","ENG":"The orphanage cannot take her in. It doesn't matter if she saved Emma's life or not.","TWN":"我們育幼院沒辦法再收留她，就算她是愛瑪的救命恩人也一樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아니, 대체 왜요? 원장님 가발에 불 붙인 바비도 받아 줬으면서!","JPN":"えっ、いったいなぜですか？　院長のカツラを燃やしたボビーだって受け入れたのに！","ENG":"Why? You even accepted Bobby, and he set your wig on fire!","TWN":"為什麼？連在院長的假髮上點火的巴比都可以留下來，為什麼她不行！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"저 아이는 출생 기록이 없어. 정부에서 보조금도 나오지 않는다는 뜻이야.","JPN":"あの子には出生記録がない。つまり、政府から補助金すら出ないということだ。","ENG":"That girl has no birth record. In other words, we can't get government funding for her.","TWN":"她沒有出生證明，政府就不會提供補助。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"기부금도 끊긴 지 오래다. 지금은 너희들을 챙기기만도 벅찬 형편이야.","JPN":"寄付金も打ち切りになってしばらく経つ。今は君たちの面倒をみるだけでも手いっぱいな状況なんだよ。","ENG":"Plus, we haven't had any donations in a while. We're already stretched thin trying to take care of you guys.","TWN":"捐款也已經中斷許久，現在光是要養活你們就已經很吃力了！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"하지만……!","JPN":"でも……！","ENG":"But…","TWN":"可是……！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"예전 원장님이 어떻게 돌아가신지 알잖니.","JPN":"前の院長がどのように亡くなったのか知っているだろう？","ENG":"Remember how my predecessor passed away?","TWN":"你知道之前的院長是怎麼死的吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"……빚 때문에 갱단들 약장사를 도와 주다 경찰 총에 맞고 돌아가셨죠.","JPN":"……借金のせいでギャングの薬売りを手伝っていたところ、警察の銃に撃たれて亡くなりました。","ENG":"…He got shot by the police while helping the gangs traffic drugs to pay off the debt.","TWN":"……因為欠錢去替幫派賣藥，結果被警察開槍打死。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"나도 예전에는 빚쟁이였다. 이자에 쪼들릴 때의 심정은 누구보다 잘 알아.","JPN":"私も以前は借金に追われていた。返済に苦しむ時の辛さは誰よりもよく知っている。","ENG":"I used to have a lot of debt myself. I understand what it's like to be hounded by interest payments.","TWN":"我以前也欠過錢，我比誰都清楚每天被利息追著跑的心情。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"호라이즌 파이낸스가 보육원을 잘 운영하는 조건으로 빚을 전부 탕감해 주지 않았으면…….","JPN":"ホライズン・ファイナンスが施設をしっかり運営するという条件で借金を全額帳消しにしてくれなかったら……","ENG":"If Horizon Finance hadn't absolved all the debt in return for keeping this orphanage running smoothly…","TWN":"要不是地平線金融說只要好好經營育幼院，就願意免除我的債務……"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"결국엔 그 양반이랑 비슷한 꼴이 됐을지도 몰라.","JPN":"今頃、前の院長と同じ目に遭っていたかもしれない。","ENG":"I might have ended up just like my predecessor.","TWN":"很可能我現在的下場就跟前任院長一樣。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"너희들은 각자가 정부에서 주는 지원금으로 생활하고 있는 거다.","JPN":"君たちはそれぞれ政府から支給される補助金で生活しているんだ。","ENG":"Everything you eat, wear, and spend is funded by the government.","TWN":"你們現在是靠政府的個人補助在過活的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"식객이 늘어날수록 너희들의 생활도 팍팍해져. 그러면 난 너희가 탈선하지 않게 돈을 빌리려 할 테고.","JPN":"子どもが増えるほど君たちの生活も苦しくなる。そうなると非行に走る子が増えて、またお金を借りるしかなくなる。","ENG":"If we get more mouths to feed, you'll go that much hungrier. And then I'll be forced to borrow money to keep you kids from turning to crime…","TWN":"吃飯的人越多，你們的生活就會窘迫，那我就勢必得去借錢來確保你們的吃喝。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"평소처럼 꼰대질이라고 해도 좋다. 하지만 난 내가 맡은 너희들을 지켜야 해.","JPN":"いつものように偉そうなジジイの説教だの言い訳だの言ってくれて構わない。だが、私は君たちの保護者である以上、守らなければならないんだ。","ENG":"You can call me a geezer, like you always do. But it's my job to take full responsibility for you children.","TWN":"就算你和平常一樣說我是老頑固也好，但我必須對你們負責任。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그…… 그렇지만 쟤도……!","JPN":"で……でもあの子だって……！","ENG":"B-but she's also…","TWN":"可……可是她……！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"어? 호라이즌? 얘가 그새 어디로 간 거야?","JPN":"あれ？　ホライズン？　いつの間にどこに消えたの？","ENG":"Huh? Horizon? Where did she go?","TWN":"嗯？地平線？怎麼突然就不見人？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그 아이라면 나랑 눈이 마주치자마자 나가더구나. 우리가 자기 얘기 하는 게 싫었겠지.","JPN":"あの子は私と目が合うやいなや出て行った。私たちが自分の話をするのが嫌だったんだろう。","ENG":"She left as soon as we made eye contact. She probably didn't like us talking about her.","TWN":"她在和我對到眼的時候就離開了，應該是不想聽我們說這些吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"원장님 바보! 대머리 꼰대 독신남! 날도 늦었는데 애가 가면 붙잡아야죠!","JPN":"院長のバカ！　ハゲ！ もう夜なのに子どもが一人で出て行くなら止めないとでしょう！","ENG":"Oh, come on, headmaster! You wrinkly old bald geezer! You should have made her stay! It's getting dark out!","TWN":"院長是大笨蛋！是禿頭古板壞心鬼！現在這麼晚，她跑出去你應該要拉住她啊！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"……저 녀석이 진짜, 자기는 천년만년 풍성할 줄 아나.","JPN":"……まったく、お前も歳を取ったらハゲるかもしれないぞ。","ENG":"Hmph… As if she'll never get any wrinkles when she hits my age…","TWN":"……那孩子真是的，還以為自己一直會這麼好過嗎？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"잠깐 실례해도 되겠습니까, 원장님?","JPN":"ちょっといいですか、院長？","ENG":"Excuse me, headmaster.","TWN":"院長，不好意思可以打擾一下嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"아, 교관님.","JPN":"ああ、教官。","ENG":"Ah, Instructor Kang.","TWN":"教官。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"정말 감사합니다. 애들한테는 위험한 곳에 들어가지 말라고 확실히 얘기해 두겠습니다.","JPN":"本当に、本当にありがとうございます。子どもたちには危険なところに入らないようにしっかり注意しておきます。","ENG":"Thank you so much. I'll be sure to teach the kids to stay away from such dangerous places.","TWN":"真是謝謝你，我會叮嚀孩子們不可以再跑到危險的地方去玩。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"편하게 부르시죠. 조정간 돌리는 법 가르쳐 준 걸로 교관님 소리 들을 자격 없습니다.","JPN":"そんなかしこまった呼び方じゃなくていいですよ。セレクターレバーの操作方法を教えたくらいで、教官と呼ばれるような立場ではありません。","ENG":"Please, just Minwoo is fine. I don't deserve to be called instructor for teaching kids how to adjust the safety lock.","TWN":"不敢當，連怎麼用槍都還是院長教我的，我哪有什麼資格當教官。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그보다 방금 전 레이첼과 하던 얘기를 우연찮게 들었는데……. 호라이즌 파이낸스에 대해 아십니까?","JPN":"それより先ほどレイチェルとの会話を偶然聞きましたが……ホライズン・ファイナンスについてご存知ですか？","ENG":"Anyway, I happened to overhear your conversation with Rachel… Are you familiar with Horizon Finance?","TWN":"只是我剛好聽到院長和瑞秋的談話……院長知道地平線金融？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"아, 그게…….","JPN":"ああ、それが……","ENG":"Oh, well…","TWN":"喔，那個……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"젊을 적 멋모르고 쓴 사채를 급하게 메꾸느라 알게 됐죠.","JPN":"若気の至りで繰り返した借金を返済する時に知ったんです。","ENG":"I was a young man, desperate for a way to pay my existing debts.","TWN":"我年輕不懂事時借過高利貸，因為想趕快把債務還清，才接觸到地平線金融的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"소문을 듣고 기겁했지만, 실제로 만나 보니 그냥 많이 무섭게 생긴 여자 분이었어요.","JPN":"噂を聞いて恐る恐る訪ねたんですが、実際に会ってみたら少し怖そうな雰囲気の女性でした。","ENG":"The rumors were frightening, but when I met their loan shark, she was just a lady… although a scary looking one at that.","TWN":"原本聽大家說完很害怕，但實際接觸後，發現只是個長得很可怕的女生。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"대표는 혹시 만나 본 적 있습니까?","JPN":"代表には会ったことあるんですか？","ENG":"Did you ever meet the owner?","TWN":"院長有見到老闆嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"아뇨. 호라이즌이란 이름만 압니다. 그 때 돈 빌린 사람들도 대부분 저랑 같을 걸요.","JPN":"いいえ、ホライズンという名前だけ知っています。あの時お金を借りた他の人たちもそうでしょう。","ENG":"No. I just know that the company's named after the owner, Horizon. I'm sure most folks who borrowed money haven't seen the owner either.","TWN":"沒有，我只知道老闆叫地平線，那時大部分去借錢的人應該都跟我一樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"어지간히 거금을 빌린 사람이 아니면 거들떠도 안 봤다더군요.","JPN":"よほどの大金の案件じゃないと顔を出さなかったらしいです。","ENG":"Word is that the owner didn't pay much attention unless you owed them big time.","TWN":"若借的金額不夠大，可是看都不看你一眼呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그런데 무슨 일이십니까? 거긴 이미 예전에…….","JPN":"ところで、それがどうしたんですか？　そこはとっくの昔に……","ENG":"But why do you ask? That place is already…","TWN":"但你怎麼會突然問起這個？那裡之前就……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아, 죄송합니다. 예전 버릇 같은 거라서요.","JPN":"すみません。昔の癖のようなもので。","ENG":"Oh, sorry. It's just an old habit of mine.","TWN":"喔，抱歉，這是我以前的職業病。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그러면…… 아까 그 호라이즌이란 아이는 어떻게 생각하십니까?","JPN":"それでは……さっきのホライズンという子はどう思いますか？","ENG":"In that case… What do you think about that girl Horizon?","TWN":"那……剛剛那個叫地平線的孩子，院長覺得怎麼樣？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"제가 잘못 들었습니까?","JPN":"私が聞き間違えましたか？","ENG":"Please tell me I misheard you.","TWN":"我有聽錯嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아니. 제대로 들었어. 보육원을 지원하자고 했지.","JPN":"いや、ちゃんと聞いたはずだ。孤児院を援助すると言った。","ENG":"No. You heard it right. I said we should support the orphanage.","TWN":"沒有，你沒聽錯，我說要贊助育幼院。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"이해할 수 없군요. 인신매매 거점으로라도 쓸 계획인가요.","JPN":"理解できませんね。人身売買の拠点としてでも使う計画ですか？","ENG":"That does not compute. Do you plan to use it as a base of operations for human trafficking?","TWN":"無法理解，還是你是想把那裡當作人口販賣的據點？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"말조심해. 아르세니코 패밀리는 그런 구질구질한 짓에 절대 손 안 댔어.","JPN":"発言に気をつけろ。\\nアルセニコファミリーはそんな汚らしいことに断じて手をつけたりはしない。","ENG":"Watch what you say. The Arsenicos never dealt in such filthy affairs.","TWN":"說話注意點，阿塞妮克家族才不會幹那種下三濫的事！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"지역 인망을 얻는 건 우리 같이 과거가 있는 사람들에게 꼭 필요한 절차야.","JPN":"地域で支持を得るのは、私たちのような過去がある人間には必ず必要なことだ。","ENG":"Earning the community's favor is essential for people with dark pasts like us.","TWN":"像我們這種過去不太光彩的人，很需要贏得當地的聲望。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그건 리타 얘기겠죠. 저는 합법적인 금융업자입니다만.","JPN":"それはリタに限った話でしょう。私は合法的な金融業者ですが。","ENG":"Speak for yourself. I run a completely legal financial operation.","TWN":"那是指你自己吧？我可是合法的金融業者。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"어느 천지의 합법적인 금융업자가 문 안 연다고 차로 들이받아.","JPN":"どこの合法的な金融業者がドアを開けないからって車で突っ込んでいくんだ。","ENG":"What kind of a legal financial operation involves ramming a door with a car just because they won't open it?","TWN":"哪間合法金融公司會因為門沒開，就直接開車撞進去？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"미사일을 쏘는 것보다는 경제적이죠. 기름값에 폐차비면 그만이니까요.","JPN":"ミサイルを撃つよりは経済的です。ガソリン代に廃車費用だけで済みますから。","ENG":"It's a much more economical alternative to missiles. One only needs to cover the cost of gas and cleanup.","TWN":"比起發射導彈，那樣比較符合經濟效益吧？只需要油錢跟車子報廢的錢。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 이자는 쥐꼬리만큼 받으면서 그따위로 장사를 했으니 이윤이 안 남지.","JPN":"そうだな。利子は雀の涙程度しかもらってないのに、そんな商売をするから利益が残らない。","ENG":"Right. And that's exactly why you barely turn a profit. The tiny interest rate doesn't help either.","TWN":"是啊，利息才收一點點，用這種方式做生意，難怪沒利潤。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"수지타산도 챙길 줄 모르는 고철 주제에 뭐하러 사채를 한다고 설쳤는지 모르겠군.","JPN":"収支の採算も気にしない鉄くずのくせに、何のために闇金業者をしているのかわからないな。","ENG":"I don't get why scrap metal like you got into the loan business in the first place. You obviously don't know a thing about money.","TWN":"真不懂，連這種簡單的收支計算都不懂的廢鐵，還學人家做什麼高利貸？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"이 직업이 휴먼들의 민낯을 가장 쉽게 관찰할 수 있기 때문이죠.","JPN":"この職業がヒューマンの素性を最も簡単に観察できるからです。","ENG":"It's because this profession offers the most intimate look at what humans are truly like.","TWN":"這是因為，放高利貸最容易觀察到人類的本性。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그리고 제 영업 방식은 논점과 거리가 멀어 보이는군요.","JPN":"そして私の営業方式は論点からかなりずれている気がしますが。","ENG":"And it seems my means of operating this business has little to do with the point.","TWN":"而且我的經營模式，和要不要贊助育幼院有什麼關係？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"……이유야 어쨌든, 우리한테 이를 갈 인간들은 득실거리고 앞으로는 더 많아질 거야.","JPN":"……理由はともかく、私たちと敵対する人間は既にわんさかいて、これからも増える一方だろう。","ENG":"…Whatever the reason, we've got plenty of folks who hate us. And there's more coming.","TWN":"……不管理由是什麼，總之以後恨我們的人只會越來越多。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그런 것들이 접근하지 못하게 걸러내려면 주변에서 도와 줘야지.","JPN":"そんな連中が安易に近づけないようにするためには、\\nある程度周りに助けてもらえる環境を作らないとな。","ENG":"We'll need some outside help to make sure those types don't get too close.","TWN":"要讓那些人無法找上我們，就需要周圍的幫助。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"포섭해서 감시망으로 사용하겠다는 겁니까?","JPN":"味方にして監視役として使うということですか？","ENG":"You mean we should recruit them to spy for us?","TWN":"你是想收買他們當作眼線嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"진공관 맙소사. 리타는 역시 잔혹무도하군요. 누가 마피아 아니랍니까.","JPN":"オーマイ、真空管。リタはやはり残酷非道ですね。さすがマフィア。","ENG":"Oh my diodes. You are indeed a cold-blooded mastermind. Spoken like a true mafiosa.","TWN":"我的真空管！不愧是麗塔，那麼地冷血！誰說你不是黑手黨的！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"닥쳐. 고철.","JPN":"黙れ、鉄くず。","ENG":"Shut up, you piece of junk.","TWN":"閉嘴，廢鐵。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"우선 우리 고객 중에는 이 놈이 제일 무난해.","JPN":"まず、うちの顧客の中だとこいつが一番無難そうだ。","ENG":"In any case, this guy's our best bet among our customers.","TWN":"在我們的客戶中，這傢伙是最適合的人選。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"월 납입금을 성실하게 납부해 온 우량 고객이군요.","JPN":"納入金を真面目に納めてきた優良顧客ですね。","ENG":"But he's an excellent customer who has been diligently paying his monthly payments.","TWN":"是每個月都有按時還款的優良客戶呢。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"훌륭한 자금원을 없애겠다니 동의하기 어렵습니다.","JPN":"立派な資金源をなくすなんて同意し難いです。","ENG":"I am reluctant to agree to removing such an outstanding source of income.","TWN":"竟然要放棄這麼棒的資金來源，我很難答應你。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"연 2.5%로 달마다 받아 봐야 푼돈이야. 수금하는 일당이 더 나오겠지.","JPN":"年2.5％で月ごとにもらっても小銭程度さ。集金する人件費のほうがもっとかかる。","ENG":"An annual interest of 2.5% is pennies. I probably make more in a single day.","TWN":"按年利率2.5%計算，每個月可以收到的錢才零頭而已。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"투자라고 생각해. 이 놈을 여기다 꽂아 두면 나중에 도움이 될 테니까.","JPN":"投資だと思え。こいつを働かせておけば後でいつか役立つだろう。","ENG":"Think of it as an investment. He'll come in handy one day if you plant him here.","TWN":"你就當作是投資嘛，把這傢伙安排在這裡，之後一定會派上用場的。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신이 옳았습니다. 리타.","JPN":"あなたが正しかったです、リタ。","ENG":"It turns out you were right, Rita.","TWN":"麗塔，你說的沒錯。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"건실하게 보육원 재정을 운용하고 있더군요. 당신의 사람 보는 눈이 정확했어요.","JPN":"堅実に孤児院の財政を運用していました。あなたの人を見る目は間違いありませんでした。","ENG":"He's been managing the orphanage's finances most prudently. You were a good judge of character.","TWN":"確實是很穩健地經營育幼院的財務。你沒看錯人。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"しかし……","ENG":"However…","TWN":"不過……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"왜 그 때는 알아채지 못한 겁니까?","JPN":"なぜ、あの時は気づかなかったのですか？","ENG":"Why couldn't you do the same later?","TWN":"那時候為什麼沒發現呢？"},"stage":{"bg":"SS_SHADOW_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"계산이 아니라, 휴먼으로서의 알량한 감에 의지했기 때문에?","JPN":"計算ではなく、信憑性のないヒューマンとしての勘に頼ったから？","ENG":"Was it because you relied on your human instincts instead of cold-blooded calculations?","TWN":"是因為不是靠著計算，而是憑著人類不可靠的第六感嗎？"},"stage":{"bg":"SS_SHADOW_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"야, 호라이즌!","JPN":"ねえ、ホライズン！","ENG":"Hey, Horizon!","TWN":"喂，地平線！"},"stage":{"bg":"SS_SHADOW_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……배웅을 요구한 적은 없었습니다만. 여기까지 왜 따라왔습니까.","JPN":"……見送りを求めたことはありませんが。なぜここまでついてきたんですか？","ENG":"…I don't recall asking you to escort me out. Why have you followed me?","TWN":"……我應該沒有要求你送我一程吧？你跟到這裡來要做什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"인사도 안 하고 가는 법이 어디 있어?","JPN":"挨拶もしないで行くなんてひどいよ！","ENG":"You didn't even say bye!","TWN":"怎麼可以不說一聲就走人？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"원장님이 저렇게 말해도 바짓가랑이 잡고 매달려야지.","JPN":"院長にあんなこと言われたって、頭を下げてでも残りたいってお願いしないとでしょ。","ENG":"I know the headmaster can be harsh, but at least you could have tried to beg.","TWN":"就算院長那麼說，你也要巴著他的大腿哀求他啊！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"내일 엠마 병원 데려다 줄 때 같이 가고 싶다고 해.","JPN":"明日エマを病院に連れて行く時、一緒に行きたいって言って。","ENG":"Tell him you'd like to tag along when we take Emma to the hospital tomorrow.","TWN":"說你明天也想一起送愛瑪去醫院！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그렇게 말하면 저래도 하룻밤은 재워 줄 거야.","JPN":"そう言えば最低でも一晩は寝かせてくれると思う。","ENG":"If you do that, he'll let you stay, at least for the night.","TWN":"院長聽到你那麼說，起碼會收留你一晚吧！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"괜찮습니다. 저는 제 사무실로 갈 겁니다.","JPN":"大丈夫です。私は自分の事務所に帰ります。","ENG":"No thank you. I will return to my office.","TWN":"沒關係，我回去我的辦公室。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"이이……!","JPN":"こ、この……！","ENG":"Argh…!","TWN":"你……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"야! 접시머리! 너 거기 서!","JPN":"おい！　皿頭！　待ってよ！","ENG":"Hey! Dish-head! Stop right there!","TWN":"喂！盤子！你給我站住！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"네. 섰습니다.","JPN":"はい、何でしょう。","ENG":"Yes? I've stopped.","TWN":"是，我站住了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"너 정말 언제까지 그럴 거야?!","JPN":"あんたさ、いつまでその設定でいる気なの？","ENG":"How long are you going to keep that up?","TWN":"你為什麼一直這樣？！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"갱단 똘마니들처럼 차려입는다고 네가 무서운 사채업자가 될 수 있을 거 같아?!","JPN":"ギャングの恰好の真似をしたって、本物のギャングや闇金業者にはなれないんだよ！","ENG":"You think you can become a loan shark just because you dress like thug?","TWN":"你以為穿得像那些幫派一樣，就可以變成可怕的高利貸嗎？！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"넌 그냥 어린애야! 누가 지켜 주지 않으면 다치거나 이용당하거나 하는 어린애라고!","JPN":"あんたはタダの子どもなの！　誰かに守ってもらわないと、ケガしたり利用されるだけの子どもなんだよ！","ENG":"You're just a kid! A kid who'll just get hurt or exploited if someone doesn't protect you!","TWN":"你就只是個小孩！若是沒有某人的保護就會受傷，或是被人利用的小孩！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"내가 그런 꼴을 이 동네에서 한두 번 본 거 같아? 마야가 오기 전에는 말도 못 했어!","JPN":"アタシがこの街に暮らしながらそんな状況を何回みたと思う？　マヤが来る前は数え切れないほどだったんだよ！","ENG":"And I've seen plenty of that happen for real! Things were even worse before Maya got here, you know!","TWN":"我看過多少孩子遇到這種事，更不用說在瑪雅來這裡之前有多可怕！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"걱정해 주고 있다는 건 이해합니다, 레이첼 도즈.","JPN":"心配してくれているのは理解します、レイチェル・ドッズ。","ENG":"I understand that you are concerned for my well-being, Rachel Dodds.","TWN":"我就解讀為你是在擔心我，瑞秋 道滋。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇지만 지금은 저보다 엠마 곁에 있는 편이 좋겠군요.","JPN":"でも今は、私よりエマのそばにいたほうがよさそうですね。","ENG":"However, I think your time is better spent next to Emma right now.","TWN":"但現在愛瑪應該比我更需要你在身邊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 당신을 멀리하는 이유는 경제적인 논리에 따르기 때문입니다.","JPN":"私があなたを遠ざける理由は、経済的な論理に従うからです。","ENG":"The reason I distance myself from you is simply economic.","TWN":"我會遠離你是根據經濟層面的判斷。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제게는 사채업자 호라이즌으로서, 해야 할 일이 남아 있습니다.","JPN":"私には闇金業者ホライズンとしてやるべきことが残っています。","ENG":"There remains something I must do as Horizon the loan shark.","TWN":"我是放高利貸的地平線，我還有事情要去完成。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그리고 그 일에 당신이 연관되는 경우는 피하고 싶군요.","JPN":"そして、その仕事にあなたが関わるのは避けたいです。","ENG":"I'd rather keep you from getting involved in that affair if I can.","TWN":"而且我不希望讓你也牽扯其中。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 보육원장의 결정을 존중합니다.","JPN":"私は院長の決定を尊重します。","ENG":"I respect the headmaster's decision.","TWN":"我尊重院長的決定。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그는 당신이 늘 말하던 것처럼 꼰대지만 자신의 책임을 떳떳하게 다하고 있으니까요.","JPN":"彼はあなたの言うとおり偉そうなジジイではありますが、自分の責任をしっかりと果たしていますからね。","ENG":"He may be an \\"old geezer\\" like you say, but he's been carrying out his responsibilities with integrity.","TWN":"他確實像你說的是個老頑固，但他非常盡忠職守。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"더는 당신의 보호자를 고민하게 만들지 마십시오. 이만 가 보겠습니다.","JPN":"これ以上あなたの保護者を悩ませないでください。私はもう行きます。","ENG":"Do not trouble your guardian any further. I'd better get going now.","TWN":"請不要再讓你的保護人感到為難，告辭。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"저, 저게……!","JPN":"ちょ､ちょっと……！","ENG":"W-why that little…!","TWN":"我……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그래! 나도 더 이상 너한테는 신경 안 쓸 거야! 이 만두 접시 꼬맹아!","JPN":"いいよ！　アタシももうあんたなんか知らないから！　この皿頭のがきんちょ！","ENG":"Fine! I'll stop giving a damn about you too, then! You plate-wearing little weirdo!","TWN":"很好！我絕對不會再替你擔心！你這饅頭盤子小鬼！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아주 평생 거기서 살아! 나쁜 놈들한테 엄청 심한 짓 당해도 모른 척 할 테니까!","JPN":"一生そこで暮らせばいい！　悪い人にひどいことされても知らないからね！","ENG":"Why don't you just live there for the rest of your life?! See if I care if the bad guys do terrible things to you!","TWN":"你就在那裡過一輩子吧！就算壞人對你做了超壞的事，我也會假裝不知道！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};